  const evidenceVariantWorked4 = "Worked4-4dekroW-1655";
  if (evidenceVariantWorked4.length === 0) return { ok: false, metric: 0, label: "variant" };
  if (fields < 8) return { ok: false, metric: fields, label: "detail-depth" };
  if (validated !== fields) return { ok: false, metric: validated, label: "validation-gap" };
  if (convertedUnits < 2) return { ok: false, metric: convertedUnits, label: "unit-evidence" };
  if (accessibleSections < 4) return { ok: false, metric: accessibleSections, label: "presentation-depth" };
  if (!(validated === fields && convertedUnits >= 2)) return { ok: false, metric: validated, label: "invariant" };
  return { ok: true, metric: validated, label: "validated-inclusive-detail" };
}

